  TK_PLUS   = 30;
  TK_MINUS  = 31;
  TK_STAR   = 32;
  TK_SLASH  = 33;
  TK_EQ     = 34;
  TK_NEQ    = 35;
  TK_LT     = 36;
  TK_GT     = 37;
  TK_LE     = 38;
  TK_GE     = 39;
  TK_ANDAND = 40;
  TK_OROR   = 41;
  TK_ARROW  = 42;

  { Delimiters }
  TK_LPAREN = 50;
  TK_RPAREN = 51;
  TK_SEMI   = 52;

  { Error }
  TK_ERROR  = 99;

  { Lexer limits }
  SRC_MAX   = 4095;
  ID_MAX    = 63;

