    begin
      if (src[pos] = '(') and (src[pos + 1] = '*') then
      begin
        depth := depth + 1;
        pos := pos + 2
      end
      else if (src[pos] = '*') and (src[pos + 1] = ')') then
      begin
        depth := depth - 1;
        pos := pos + 2
      end
      else
        pos := pos + 1
    end;
    skip_comment := true
  end
end;

