        begin
          tok := TK_LE;
          pos := pos + 1
        end
        else
          tok := TK_LT
      end;
    '>':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '=') then
        begin
          tok := TK_GE;
          pos := pos + 1
        end
        else
          tok := TK_GT
      end;
    '&':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '&') then
        begin
          tok := TK_ANDAND;
          pos := pos + 1
        end
        else
        begin
          tok := TK_ERROR;
